13→class StackTraceRecoveryNestedTest : TestBase() {
14→
15→    @Test
16→    fun testNestedAsync() = runTest {
17→        val rootAsync = async(NonCancellable) {
18→            expect(1)
19→
20→            // Just a noise for unwrapping
21→            async {
22→                expect(2)
23→                delay(Long.MAX_VALUE)
24→            }
25→
26→            // Do not catch, fail on cancellation
27→            async {
28→                expect(3)
29→                async {
30→                    expect(4)
31→                    delay(Long.MAX_VALUE)
32→                }
33→
34→                async {
35→                    expect(5)
36→                    // 1) await(), catch, verify and rethrow
37→                    try {
38→                        val nested = async {
39→                            expect(6)
40→                            throw RecoverableTestException()
41→                        }
42→
43→                        nested.awaitNested()
44→                    } catch (e: RecoverableTestException) {
45→                        expect(7)
46→                        e.verifyException(
47→                            "await\$suspendImpl",
48→                            "awaitNested",
49→                            "\$testNestedAsync\$1\$rootAsync\$1\$2\$2.invokeSuspend"
50→                        )
51→                        // Just rethrow it
52→                        throw e
53→                    }
54→                }
55→            }
56→        }
57→
58→        try {
59→            rootAsync.awaitRootLevel()
60→        } catch (e: RecoverableTestException) {
61→            e.verifyException("awaitRootLevel")
62→            finish(8)
63→        }
64→    }
65→
66→    private suspend fun Deferred<*>.awaitRootLevel() {
67→        await()
68→        assertTrue(true)
69→    }
70→
71→    private suspend fun Deferred<*>.awaitNested() {
72→        await()
73→        assertTrue(true)
74→    }
75→
76→    private fun RecoverableTestException.verifyException(vararg expectedTraceElements: String) {
77→        // It is "recovered" only once
78→        assertEquals(1, depth())
79→        val stacktrace = stackTrace.map { it.methodName }.toSet()
80→        assertTrue(expectedTraceElements.all { stacktrace.contains(it) })
81→    }
82→
83→    private fun Throwable.depth(): Int {
84→        val cause = cause ?: return 0
85→        return 1 + cause.depth()
86→    }
87→}
